RAW_MATERIAL_ITEMS.forEach(function(m){var v=pdb[m.id]||(tpl.rawMaterials.find(function(r){return r.id===m.id})||{}).unitPrice||0;h+='<tr><td style="padding:3px 6px;font-size:11px;color:#F5F5F7;">'+m.name+'</td><td style="padding:3px 4px;"><input type="number" id="pdb_'+m.id+'" step="0.1" min="0" value="'+v+'" oninput="window._autoSavePDB()" style="width:100%;background:rgba(255,255,255,0.06);color:#F5F5F7;border:1px solid rgba(255,255,255,0.1);border-radius:4px;padding:3px 6px;font-size:11px;text-align:right;"></td></tr>'});
h+='</tbody></table>';
