var cpDB=pdb._colors||{};ALL_COLORS.forEach(function(c,i){h+='<tr><td style="padding:2px 6px;font-size:11px;color:#BF5AF2;font-weight:600;">'+c.n+'</td><td style="padding:2px 6px;font-size:10px;color:#636366;">'+c.d+'</td><td style="padding:2px 4px;"><input type="number" id="cprice_'+i+'" step="0.1" min="0" value="'+(cpDB[c.n]||0)+'" oninput="window._autoSavePDB()" style="width:100%;background:rgba(255,255,255,0.06);color:#F5F5F7;border:1px solid rgba(255,255,255,0.1);border-radius:4px;padding:2px 6px;font-size:11px;text-align:right;"></td></tr>'});
h+='</tbody></table>';
h+='<div style="font-size:11px;font-weight:700;color:#64D2FF;margin:16px 0 6px;">вҡЎ иғҪжәҗ</div>';
ENERGY_ITEMS.forEach(function(u){var v=pdb['energy_'+u.id]||0;h+='<div style="display:flex;justify-content:space-between;padding:3px 0;"><span style="font-size:12px;color:#F5F5F7;">'+u.name+' (NTD/'+u.unit+')</span><input type="number" id="pdb_energy_'+u.id+'" step="0.01" min="0" value="'+v+'" oninput="window._autoSavePDB()" style="width:100px;background:rgba(255,255,255,0.06);color:#F5F5F7;border:1px solid rgba(255,255,255,0.1);border-radius:4px;padding:3px 6px;font-size:11px;text-align:right;"></div>'});
h+='<div style="display:flex;gap:8px;margin-top:16px;justify-content:flex-end;"><button onclick="window._applyPDB();document.getElementById(\'pdbOverlay\').remove()" style="padding:6px 16px;background:rgba(48,209,88,0.1);border:1px solid rgba(48,209,88,0.3);border-radius:6px;color:#30D158;font-size:12px;font-weight:600;cursor:pointer;">рҹ’ҫ е„ІеӯҳдёҰеҘ—з”Ё</button><button onclick="document.getElementById(\'pdbOverlay\').remove()" style="padding:6px 16px;background:rgba(255,255,255,0.04);border:1px solid rgba(255,255,255,0.1);border-radius:6px;color:#98989D;font-size:12px;cursor:pointer;">й—ңй–ү</button></div></div>';
